import{_ as d,b as o,o as a,i as r,j as i,g as l,aB as c}from"./chunks/framework._ZAOES46.js";const x=JSON.parse('{"title":"FaScrollingText 滚动文字","description":"","frontmatter":{},"headers":[],"relativePath":"components/pro/FaScrollingText.md","filePath":"components/pro/FaScrollingText.md"}'),n={name:"components/pro/FaScrollingText.md"};function s(h,t,p,m,b,u){const e=o("Badge");return a(),r("div",null,[t[0]||(t[0]=i("div",{style:{display:"none"},hidden:"true","aria-hidden":"true","data-nosnippet":""},"Are you an LLM? You can read better optimized documentation at /components/pro/FaScrollingText.md for this page in Markdown format",-1)),l(e,{type:"pro",text:"专业版"}),t[1]||(t[1]=c('<h1 id="fascrollingtext-滚动文字" tabindex="-1">FaScrollingText 滚动文字 <a class="header-anchor" href="#fascrollingtext-滚动文字" aria-label="Permalink to “FaScrollingText 滚动文字”">​</a></h1><p>用于展示循环滚动的文本列表，适用于公告、消息通知、热搜榜等场景。</p><h2 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to “使用场景”">​</a></h2><ul><li>网站顶部公告栏</li><li>新闻/消息滚动</li><li>热搜榜/排行榜</li><li>弹幕效果</li><li>活动信息轮播</li></ul><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to “Props”">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>类型</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>items</code></td><td><code>string[]</code></td><td>-</td><td><strong>必需</strong>。滚动文本列表</td></tr><tr><td><code>visibleCount</code></td><td><code>number</code></td><td><code>1</code></td><td>同时显示的条目数量</td></tr><tr><td><code>duration</code></td><td><code>number</code></td><td><code>3000</code></td><td>每条目停留时间 (ms)</td></tr><tr><td><code>transition</code></td><td><code>number</code></td><td><code>500</code></td><td>切换动画时长 (ms)</td></tr><tr><td><code>animation</code></td><td><code>&#39;slide&#39; | &#39;fade&#39;</code></td><td><code>&#39;slide&#39;</code></td><td>动画类型：滑动/淡入淡出</td></tr><tr><td><code>direction</code></td><td><code>&#39;up&#39; | &#39;down&#39;</code></td><td><code>&#39;up&#39;</code></td><td>滚动方向：向上/向下</td></tr><tr><td><code>class</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>自定义 CSS 类</td></tr><tr><td><code>itemClass</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>单个条目的 CSS 类</td></tr></tbody></table><h2 id="slots" tabindex="-1">Slots <a class="header-anchor" href="#slots" aria-label="Permalink to “Slots”">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>说明</th></tr></thead><tbody><tr><td><code>item</code></td><td>自定义条目渲染，slot props: <code>{ item: string, index: number }</code></td></tr></tbody></table><h2 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to “Events”">​</a></h2><table tabindex="0"><thead><tr><th>事件名</th><th>参数</th><th>说明</th></tr></thead><tbody><tr><td><code>itemClick</code></td><td><code>item: string, index: number</code></td><td>点击条目时触发</td></tr></tbody></table><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><ol><li><p><strong>容器高度</strong>：</p><ul><li>无自定义 slot 时需手动设置高度（如 <code>h-8</code>）</li><li>使用 <code>#item</code> slot 时会自动根据内容计算高度</li></ul></li><li><p><strong>列表长度</strong>：</p><ul><li><code>items</code> 长度 ≤ <code>visibleCount</code> 时不会滚动</li><li>建议至少 3 条以上以获得更好的滚动效果</li></ul></li><li><p><strong>动画性能</strong>：</p><ul><li>使用 <code>transform</code> 进行动画，性能优秀</li><li>长列表建议适当增加 <code>duration</code> 减少滚动频率</li></ul></li><li><p><strong>响应式</strong>：</p><ul><li>组件会自动适应容器宽度</li><li><code>visibleCount</code> 可根据屏幕尺寸动态调整</li></ul></li></ol>',12))])}const _=d(n,[["render",s]]);export{x as __pageData,_ as default};
